import { type PropsWithChildren } from 'react';

import {
  container,
  tooltipOverlay,
  tooltipOverlayFull,
  consumerLoadingStyle,
} from './GaugeLayoutOverlay.sty.js';
import { Flex } from '../../../../layouts/flex/Flex.js';
import { LoaderOverlay } from '../../../core/components/loader-overlay/LoaderOverlay.js';
import { useOverlay } from '../../../core/components/overlay-tooltip/contexts/OverlayContext.js';
import { useTooltipActions } from '../../../core/components/overlay-tooltip/useTooltipActions.js';
import { useGaugeChartTooltip } from '../../contexts/GaugeChartTooltipContext.js';
import { useGaugeChartTooltipOverlayBounds } from '../../hooks/useGaugeChartTooltipOverlayBounds.js';
import {
  GaugeChartToolbar,
  type GaugeChartToolbarProps,
} from '../GaugeChartLayout/GaugeChartToolbar.js';
import { GaugeOverlayTooltip } from '../GaugeChartTooltip/GaugeOverlayTooltip.js';

interface GaugeChartOverlayProps {
  value: number;
  color: string;
  showLoading?: boolean;
  intents: GaugeChartToolbarProps['intents'];
  toolbar: GaugeChartToolbarProps['toolbar'];
}

export const GaugeChartOverlay = (
  props: PropsWithChildren<GaugeChartOverlayProps>,
) => {
  const { children, value, color, intents, toolbar, showLoading } = props;
  const overlay = useOverlay();
  const overlayBounds = useGaugeChartTooltipOverlayBounds();
  const { name: tooltipName, hidden: tooltipHidden } = useGaugeChartTooltip();
  const { hover, togglePin, outOfBounds } = useTooltipActions();

  const data = {
    geometry: 'meterbar' as const,
    series: [{ name: tooltipName ?? 'Value', value, color }],
  };

  const overlayClassName = overlayBounds
    ? tooltipOverlay
    : `${tooltipOverlay} ${tooltipOverlayFull}`;
  const overlayStyle = overlayBounds
    ? {
        top: overlayBounds.top,
        left: overlayBounds.left,
        width: overlayBounds.width,
        height: overlayBounds.height,
      }
    : undefined;

  return (
    <Flex
      ref={overlay.overlayRef}
      data-testid="gauge-overlay-wrapper"
      className={container({ showLoading })}
    >
      <GaugeChartToolbar intents={intents} toolbar={toolbar} />

      {!showLoading && (
        <Flex
          className={overlayClassName}
          onPointerMove={(event) => hover(event, data)}
          onPointerLeave={outOfBounds}
          onClick={(event) => togglePin(event, data)}
          style={overlayStyle}
        >
          {!tooltipHidden && (
            <GaugeOverlayTooltip value={value} color={color} />
          )}
        </Flex>
      )}

      {children}
      {showLoading ? (
        <LoaderOverlay
          gridArea="1/1/2/2"
          consumerStyle={consumerLoadingStyle}
        />
      ) : null}
    </Flex>
  );
};

GaugeChartOverlay['displayName'] = 'GaugeChartOverlay';
